using Payments;

namespace PaymentGateway.Tests;

[TestClass]
public sealed class PaymentGatewayTests
{
    private readonly Payments.PaymentGateway _gateway;

    public PaymentGatewayTests()
    {
        _gateway = new Payments.PaymentGateway();
    }

    // ── ChargeAsync ────────────────────────────────────────────────

    [TestMethod]
    public async Task ChargeAsync_ValidCard_ReturnsSuccessWithChargeId()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", 49.99m);

        Assert.IsTrue(result.Success);
        Assert.IsNotNull(result.ChargeId);
    }

    [TestMethod]
    public async Task ChargeAsync_ValidCard_ReturnsNonEmptyChargeId()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", 100m);

        Assert.IsTrue(result.Success);
        Assert.AreNotEqual(string.Empty, result.ChargeId);
    }

    [TestMethod]
    [DataRow(0)]
    [DataRow(-1)]
    [DataRow(-100.50)]
    public async Task ChargeAsync_ZeroOrNegativeAmount_ThrowsArgumentException(double amount)
    {
        await Assert.ThrowsExactlyAsync<ArgumentException>(
            async () => await _gateway.ChargeAsync("tok_valid_visa", (decimal)amount));
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public async Task ChargeAsync_NullOrEmptyToken_ThrowsArgumentException(string? token)
    {
        await Assert.ThrowsExactlyAsync<ArgumentException>(
            async () => await _gateway.ChargeAsync(token!, 10m));
    }

    [TestMethod]
    public async Task ChargeAsync_DeclinedCard_ReturnsFailure()
    {
        var result = await _gateway.ChargeAsync("tok_declined", 50m);

        Assert.IsFalse(result.Success);
    }

    [TestMethod]
    public async Task ChargeAsync_MinimumAmount_Succeeds()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", 0.01m);

        Assert.IsTrue(result.Success);
    }

    [TestMethod]
    public async Task ChargeAsync_LargeAmount_Succeeds()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", 999_999.99m);

        Assert.IsTrue(result.Success);
    }

    [TestMethod]
    public async Task ChargeAsync_TwoCalls_ReturnDifferentChargeIds()
    {
        var result1 = await _gateway.ChargeAsync("tok_valid_visa", 10m);
        var result2 = await _gateway.ChargeAsync("tok_valid_visa", 20m);

        Assert.AreNotEqual(result1.ChargeId, result2.ChargeId);
    }

    // ── RefundAsync ────────────────────────────────────────────────

    [TestMethod]
    public async Task RefundAsync_ValidChargeId_ReturnsSuccessWithRefundId()
    {
        var charge = await _gateway.ChargeAsync("tok_valid_visa", 25m);
        var refund = await _gateway.RefundAsync(charge.ChargeId);

        Assert.IsTrue(refund.Success);
        Assert.IsNotNull(refund.RefundId);
    }

    [TestMethod]
    public async Task RefundAsync_ValidChargeId_ReturnsNonEmptyRefundId()
    {
        var charge = await _gateway.ChargeAsync("tok_valid_visa", 25m);
        var refund = await _gateway.RefundAsync(charge.ChargeId);

        Assert.AreNotEqual(string.Empty, refund.RefundId);
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public async Task RefundAsync_NullOrEmptyChargeId_ThrowsArgumentException(string? chargeId)
    {
        await Assert.ThrowsExactlyAsync<ArgumentException>(
            async () => await _gateway.RefundAsync(chargeId!));
    }

    [TestMethod]
    public async Task RefundAsync_NonExistentChargeId_ReturnsFailure()
    {
        var result = await _gateway.RefundAsync("ch_does_not_exist");

        Assert.IsFalse(result.Success);
    }

    [TestMethod]
    public async Task RefundAsync_TwoRefunds_ReturnDifferentRefundIds()
    {
        var charge1 = await _gateway.ChargeAsync("tok_valid_visa", 10m);
        var charge2 = await _gateway.ChargeAsync("tok_valid_visa", 20m);

        var refund1 = await _gateway.RefundAsync(charge1.ChargeId);
        var refund2 = await _gateway.RefundAsync(charge2.ChargeId);

        Assert.AreNotEqual(refund1.RefundId, refund2.RefundId);
    }
}

